@app.route('/callback')
def callback():
    """Handle the OIDC callback after user authentication."""
    # Check for error response from the provider
    error = request.args.get('error')
    if error:
        error_description = request.args.get('error_description', 'Unknown error')
        logger.warning(f"OIDC error response: {error}")
        return jsonify({'error': 'Authentication failed', 'description': error_description}), 400

    # Validate required parameters are present
    code = request.args.get('code')
    state = request.args.get('state')

    if not code or not state:
        logger.warning("Missing code or state in callback")
        return jsonify({'error': 'Invalid callback parameters'}), 400

    # CRITICAL: Validate state parameter to prevent CSRF
    stored_state = session.pop('oidc_state', None)
    if stored_state is None:
        logger.warning("No stored state found in session")
        return jsonify({'error': 'Invalid session state'}), 400

    if not hmac.compare_digest(str(state), str(stored_state)):
        logger.warning("State parameter mismatch - possible CSRF attack")
        return jsonify({'error': 'State validation failed'}), 400

    # Retrieve the stored nonce for ID token validation
    stored_nonce = session.pop('oidc_nonce', None)
    if stored_nonce is None:
        logger.warning("No stored nonce found in session")
        return jsonify({'error': 'Invalid session state'}), 400

    # Check that the auth flow hasn't been pending too long (5 minutes max)
    auth_started = session.pop('oidc_auth_started', None)
    if auth_started and (time.time() - auth_started) > 300:
        logger.warning("Authorization flow took too long")
        return jsonify({'error': 'Authorization flow expired'}), 400

    # Exchange authorization code for tokens
    discovery = get_oidc_discovery()

    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
    }

    try:
        token_response = requests.post(
            discovery['token_endpoint'],
            data=token_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'},
            timeout=10,
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.RequestException as e:
        logger.error("Failed to exchange authorization code for tokens")
        return jsonify({'error': 'Token exchange failed'}), 500
    except json.JSONDecodeError:
        logger.error("Invalid JSON response from token endpoint")
        return jsonify({'error': 'Invalid token response'}), 500

    # Validate required tokens are present
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')

    if not id_token:
        logger.error("No id_token in token response")
        return jsonify({'error': 'Missing id_token'}), 500

    # CRITICAL: Validate and decode the ID token with nonce verification
    try:
        claims = validate_and_decode_id_token(id_token, stored_nonce, access_token)
    except ValueError as e:
        logger.warning(f"ID token validation failed: {str(e)}")
        return jsonify({'error': 'ID token validation failed'}), 400

    # Extract user information from validated claims
    # Only store necessary, non-sensitive information in the session
    user_info = {
        'sub': claims.get('sub'),
        'name': claims.get('name', ''),
        'email': claims.get('email', ''),
        'email_verified': claims.get('email_verified', False),
    }

    # Optionally fetch additional user info from the userinfo endpoint
    if access_token and 'userinfo_endpoint' in discovery:
        try:
            userinfo_response = requests.get(
                discovery['userinfo_endpoint'],
                headers={'Authorization': f'Bearer {access_token}'},
                timeout=10,
            )
            if userinfo_response.status_code == 200:
                userinfo = userinfo_response.json()
                # Validate that the sub claim matches
                if userinfo.get('sub') == claims.get('sub'):
                    user_info['name'] = userinfo.get('name', user_info['name'])
                    user_info['email'] = userinfo.get('email', user_info['email'])
                    user_info['email_verified'] = userinfo.get('email_verified', user_info['email_verified'])
                else:
                    logger.warning("UserInfo sub does not match ID token sub")
        except (requests.RequestException, json.JSONDecodeError):
            # UserInfo is supplementary; continue with ID token claims
            logger.info("Failed to fetch userinfo, continuing with ID token claims")

    # Store user info in session
    session['user'] = user_info
    session['auth_time'] = time.time()
    session.permanent = True

    # Do NOT store tokens in the session unless absolutely necessary
    # If refresh tokens are needed, store them securely (e.g., encrypted in a database)

    logger.info(f"User authenticated successfully: sub={user_info['sub']}")

    return redirect(url_for('profile'))


